{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem asks for a proof of the sharpness of the De Giorgi recurrence exponent $\\beta = 4/3$ for the 3D Navier-Stokes equations. This requires a sophisticated construction of a counterexample (extremizer) and a systematic elimination of alternative mathematical approaches.",
  "helpers": [
    {
      "label": "extremizer_construction",
      "instructions": "Construct a specific solution (or a sequence of approximate solutions) to the 3D Navier-Stokes equations that demonstrates the sharpness of the exponent $\\beta = 4/3$. This involves defining the scaling properties and the specific blow-up profile that prevents any exponent $\\beta > 4/3$ from being valid."
    },
    {
      "label": "alternative_route_elimination",
      "instructions": "Systematically analyze and provide mathematical arguments for why the 8 standard alternative routes (typically involving different energy inequalities, scaling arguments, or regularity criteria) fail to improve the exponent. For each route, identify the specific mathematical obstruction (e.g., failure of a specific embedding, loss of control over a non-linear term, or violation of a scaling law)."
    },
    {
      "label": "exponent_verification",
      "instructions": "Perform the formal calculation to verify that the constructed extremizer satisfies the Navier-Stokes equations (or is a valid limit) and that its decay/growth rate corresponds exactly to $\\beta = 4/3$, thereby proving no larger exponent is possible."
    }
  ],
  "synthesis_brief": "Combine the construction of the extremizer with the rigorous elimination of the 8 alternative routes. The final answer must conclude that the exponent cannot be improved, supported by the specific construction and the proof that all other paths to improvement are blocked."
}
```

